{"description":"class Agent:
    def __init__(self, llm, tools, system_prompt):
        self.llm = llm
        self.tools = tools                  # dict[name → tool_fn]
        self.memory = []                    # list of messages
        self.system_prompt = system_prompt

    def run(self, user_goal: str) → str:
        self.memory = [{"role": "system", "content": self.system_prompt}]
        self.memory.append({"role": "user",   "content": user_goal})

        max_steps = 20

        for step in range(max_steps):
            thought = self._think()                     # LLM call

            if "Final Answer" in thought:
                return self._extract_final_answer(thought)

            action, action_input = self._parse_action(thought)

            if action == "Finish":
                return action_input

            if action not in self.tools:
                observation = f"Error: Unknown tool '{action}'"
            else:
                observation = self._execute_tool(action, action_input)

            self.memory.append({"role": "assistant", "content": thought})
            self.memory.append({"role": "observation", "content": observation})

        return "✗ Max steps exceeded"


    def _think(self) -> str:
        return self.llm.chat(self.memory)


    def _execute_tool(self, name: str, input_str: str) -> str:
        try:
            return str(self.tools[name](input_str))
        except Exception as e:
            return f"Tool failed: {e}"


